import React, { useEffect, useState } from "react";
import { Table, Button, Tooltip } from "antd";
import { Trash2, Plus, Search, Pencil, Layers, Hash } from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import {
  deleteABlogSubCategory,
  getSubCategories,
  resetState,
} from "../features/bSubCategory/bSubCategorySlice";
import CustomModal from "../components/CustomModal";

const Subcategorylist = () => {
  const [open, setOpen] = useState(false);
  const [pCatId, setpCatId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setpCatId(e);
  };

  const hideModal = () => setOpen(false);

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(resetState());
    dispatch(getSubCategories());
  }, [dispatch]);

  const bSubCatStat = useSelector((state) => state.bSubcategory.bSubCategories);

  const columns = [
    {
      title: "ID",
      dataIndex: "key",
      width: 90,
      render: (text) => (
        <span className="font-mono text-[11px] font-black text-slate-400 bg-slate-50 px-2.5 py-1 rounded-lg border border-slate-100 uppercase tracking-widest">
          SUB-{String(text).padStart(3, "0")}
        </span>
      ),
    },
    {
      title: "Sub-Category Name",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600 border border-blue-100 flex-shrink-0">
            <Hash size={16} />
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-slate-900 text-[15px] tracking-tight">{text}</span>
            <span className="text-[11px] text-slate-400 font-medium">Blog Sub-Category</span>
          </div>
        </div>
      ),
      sorter: (a, b) => a.name.localeCompare(b.name),
    },
    {
      title: "Actions",
      dataIndex: "action",
      width: 110,
      render: (_, record) => (
        <div className="flex items-center gap-2">
          <Link to={`/admin/blogSubcategory/${record._id}`}>
            <Tooltip title="Edit">
              <Button
                type="text"
                icon={<Pencil size={16} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-10 h-10 flex items-center justify-center transition-all border border-transparent hover:border-blue-100"
              />
            </Tooltip>
          </Link>
          <Tooltip title="Delete">
            <Button
              type="text"
              icon={<Trash2 size={16} />}
              onClick={() => showModal(record._id)}
              className="text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl w-10 h-10 flex items-center justify-center transition-all border border-transparent hover:border-rose-100"
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const data1 =
    bSubCatStat
      ?.filter(
        (s) =>
          !searchText ||
          s.title.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((sub, i) => ({
        key: i + 1,
        _id: sub._id,
        name: sub.title,
      })) || [];

  const deleteCategory = (e) => {
    dispatch(deleteABlogSubCategory(e));
    toast.success("Sub-category deleted");
    setOpen(false);
    setTimeout(() => dispatch(getSubCategories()), 500);
  };

  return (
    <div className="space-y-8 pb-12 page-enter">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <Layers size={18} className="text-blue-600" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-widest">Content</span>
          </div>
          <h1 className="text-[28px] font-bold text-slate-900">Blog Sub-Categories</h1>
          <p className="text-[14px] text-slate-500 mt-1">Manage granular blog content classifications.</p>
        </div>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="relative flex-1 sm:flex-none">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input
              type="text"
              placeholder="Search sub-categories..."
              className="pl-10 pr-4 h-11 w-full sm:w-64 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 text-[14px] font-medium"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <Link to="/admin/blogSubcategory">
            <Button
              type="primary"
              className="rounded-xl h-11 bg-[#1e3a8a] text-white font-bold text-[14px] px-6 border-none flex items-center gap-2 shadow-sm"
            >
              <Plus size={18} /> Add New
            </Button>
          </Link>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
        <div className="flex items-center gap-4 p-6 border-b border-slate-50">
          <div className="p-2.5 bg-blue-50 rounded-xl text-blue-600">
            <Layers size={18} />
          </div>
          <div>
            <span className="text-[15px] font-bold text-slate-900 border-slate-100 pr-4 mr-4 border-r">
              Sub-Category Registry
            </span>
            <span className="text-[13px] text-slate-500 font-medium">
              Total: <span className="text-slate-900 font-bold">{data1.length}</span>
            </span>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={data1}
          pagination={{ pageSize: 12, className: "px-6 py-4" }}
          className="modern-table"
          scroll={{ x: true }}
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteCategory(pCatId)}
        title="Delete Sub-Category"
        content="Are you sure you want to delete this sub-category? This action cannot be undone."
      />
    </div>
  );
};

export default Subcategorylist;
